function closeDesigner(){document.getElementById('designerModal').classList.remove('open')}




/* ===== FIREBASE AUTH SYSTEM ===== */
let currentUser = null;

// Called when Firebase auth state changes → user logged in
window._onFbLogin = async function(fbUser) {
  currentUser = fbUser;
  updateAuthBtn();
  showToast('👋 Welcome, ' + (currentUser.name.split(' ')[0] || 'back') + '!');
};

// Called when Firebase logs out
window._onFbLogout = function() {
  currentUser = null;
  updateAuthBtn();
};

// Fallback: localStorage for offline/demo mode
function getUsers(){try{return JSON.parse(localStorage.getItem('a3m_users')||'{}')}catch{return {}}}
function saveUsers(u){localStorage.setItem('a3m_users',JSON.stringify(u))}
function saveSession(u){localStorage.setItem('a3m_session',JSON.stringify(u))}
function clearSession(){localStorage.removeItem('a3m_session')}
function loadSession(){try{const s=localStorage.getItem('a3m_session');return s?JSON.parse(s):null}catch{return null}}

function openAuth(){
  if(currentUser) openMyAccount(); else showAuthModal();
}
function showAuthModal(){
  document.getElementById('authModal').style.display='flex';
  switchAuthTab('login');
}
function closeAuth(){document.getElementById('authModal').style.display='none'}
function openProfile(){openMyAccount()}
function closeProfile(){closeMyAccount()}

function isFirebaseReady(){return window._fb && window._fb.ready();}

/* ---- Auth loading state ---- */
function setAuthLoading(btnId, loading, text){
  const btn = document.getElementById(btnId);
  if(!btn) return;
  btn.disabled = loading;
  btn.style.opacity = loading ? '.6' : '1';
  btn.style.cursor = loading ? 'wait' : 'pointer';
  if(text) btn.textContent = text;
}

function switchAuthTab(tab){
  document.getElementById('loginForm').style.display=tab==='login'?'block':'none';
  document.getElementById('signupForm').style.display=tab==='signup'?'block':'none';
  document.getElementById('forgotForm').style.display=tab==='forgot'?'block':'none';
  const tl=document.getElementById('tabLogin'),ts=document.getElementById('tabSignup');
  tl.style.color=tab==='login'?'var(--accent)':'var(--txt3)';
  tl.style.borderBottomColor=tab==='login'?'var(--accent)':'transparent';
  ts.style.color=tab==='signup'?'var(--accent)':'var(--txt3)';
  ts.style.borderBottomColor=tab==='signup'?'var(--accent)':'transparent';
  document.getElementById('authSubtitle').textContent=tab==='login'?'Sign in to your account':tab==='signup'?'Create your free account':'Reset password';
  clearAuthErrors();
}
function showForgot(){switchAuthTab('forgot')}
function clearAuthErrors(){
  ['loginError','signupError','forgotError'].forEach(id=>{const e=document.getElementById(id);if(e)e.style.display='none'});
}
function showError(id,msg){
  const e=document.getElementById(id);if(!e)return;
  e.textContent=msg;e.style.display='block';
}
function togglePw(inputId,btn){
  const el=document.getElementById(inputId);
  el.type=el.type==='password'?'text':'password';
  btn.textContent=el.type==='password'?'👁':'🙈';
}
function checkPwStrength(pw){
  const fill=document.getElementById('pwStrengthFill');
  const lbl=document.getElementById('pwStrengthLabel');
  if(!fill)return;
  let score=0;
  if(pw.length>=6)score++;if(pw.length>=10)score++;
  if(/[A-Z]/.test(pw))score++;if(/[0-9]/.test(pw))score++;if(/[^A-Za-z0-9]/.test(pw))score++;
  const map=[[20,'#ef4444','Weak'],[40,'#f97316','Fair'],[60,'#eab308','Good'],[80,'#22c55e','Strong'],[100,'#16a34a','Very Strong']];
  const [w,c,t]=map[Math.min(score,4)];
  fill.style.width=w+'%';fill.style.background=c;lbl.textContent=pw?t:'';lbl.style.color=c;
}

/* ---- Firebase error messages (Arabic-friendly) ---- */
function fbErrMsg(code){
  const map = {
    'auth/email-already-in-use': '❌ Email already registered. Try logging in.',
    'auth/invalid-email': '❌ Invalid email address.',
    'auth/weak-password': '❌ Password too weak (min 6 chars).',
    'auth/user-not-found': '❌ No account with this email.',
    'auth/wrong-password': '❌ Wrong password.',
    'auth/invalid-credential': '❌ Wrong email or password.',
    'auth/too-many-requests': '⚠️ Too many attempts. Try later.',
    'auth/network-request-failed': '⚠️ Network error. Check connection.',
    'auth/popup-closed-by-user': '⚠️ Google login cancelled.',
  };
  return map[code] || ('❌ Error: ' + code);
}

/* ---- Login ---- */
async function doLogin(){
  const email = document.getElementById('loginUser').value.trim();
  const p = document.getElementById('loginPass').value;
  if(!email||!p){showError('loginError','⚠️ Fill all fields.');return;}
  clearAuthErrors();
  setAuthLoading('loginBtn', true, '⏳ Logging in...');
  if(isFirebaseReady()){
    try {
      await window._fb.login(email, p);
      closeAuth();
      showToast('✅ Logged in!');
    } catch(e) {
      showError('loginError', fbErrMsg(e.code));
    }
  } else {
    // Offline fallback
    const users=getUsers();
    const key=Object.keys(users).find(k=>users[k].email===email||k===email);
    if(!key||users[key].password!==btoa(p)){showError('loginError','❌ Wrong email or password.');setAuthLoading('loginBtn',false,'🔑 Login');return;}
    currentUser={...users[key]};saveSession(currentUser);updateAuthBtn();closeAuth();showToast('👋 Welcome back!');
  }
  setAuthLoading('loginBtn', false, '🔑 Login');
}

/* ---- Google Login ---- */
async function doGoogleLogin(){
  if(!isFirebaseReady()){showToast('⚠️ Firebase not configured yet');return;}
  clearAuthErrors();
  setAuthLoading('googleBtn', true, '⏳ Opening Google...');
  try {
    await window._fb.loginGoogle();
    closeAuth();
    showToast('✅ Signed in with Google!');
  } catch(e) {
    showError('loginError', fbErrMsg(e.code));
  }
  setAuthLoading('googleBtn', false, '🔑 Continue with Google');
}

/* ---- Sign Up ---- */
async function doSignup(){
  const name = document.getElementById('signupName').value.trim();
  const email = document.getElementById('signupEmail').value.trim();
  const phone = document.getElementById('signupPhone').value.trim();
  const p = document.getElementById('signupPass').value;
  const p2 = document.getElementById('signupPass2').value;
  if(!email||!p||!p2){showError('signupError','⚠️ Email and password required.');return;}
  if(p.length<6){showError('signupError','⚠️ Password min 6 characters.');return;}
  if(p!==p2){showError('signupError','⚠️ Passwords do not match.');return;}
  clearAuthErrors();
  setAuthLoading('signupBtn', true, '⏳ Creating account...');
  if(isFirebaseReady()){
    try {
      await window._fb.register(email, p, name||email.split('@')[0], phone);
      closeAuth();
      showToast('🎉 Account created! Welcome!');
    } catch(e) {
      showError('signupError', fbErrMsg(e.code));
    }
  } else {
    // Offline fallback
    const users=getUsers();
    if(users[email]){showError('signupError','❌ Email already taken.');setAuthLoading('signupBtn',false,'✨ Create Account');return;}
    users[email]={email,name:name||email.split('@')[0],phone,password:btoa(p),joined:new Date().toLocaleDateString(),orders:0,followers:0,following:0,designsPublished:0,designsSold:0};
    saveUsers(users);currentUser={...users[email]};saveSession(currentUser);updateAuthBtn();closeAuth();showToast('🎉 Welcome!');
  }
  setAuthLoading('signupBtn', false, '✨ Create Account');
}

/* ---- Forgot Password ---- */
async function doForgot(){
  const email = document.getElementById('forgotUser').value.trim();
  if(!email){showError('forgotError','⚠️ Enter your email.');return;}
  clearAuthErrors();
  setAuthLoading('forgotBtn', true, '⏳ Sending...');
  if(isFirebaseReady()){
    try {
      await window._fb.resetPassword(email);
      document.getElementById('forgotMsg').style.display='block';
      document.getElementById('forgotMsg').textContent='✅ Reset email sent! Check your inbox.';
    } catch(e) {
      showError('forgotError', fbErrMsg(e.code));
    }
  } else {
    document.getElementById('forgotMsg').style.display='block';
    document.getElementById('forgotMsg').textContent='⚠️ Firebase not configured. Reset unavailable offline.';
  }
  setAuthLoading('forgotBtn', false, '📧 Send Reset Email');
}

/* ---- Logout ---- */
async function doLogout(){
  if(isFirebaseReady()){ try { await window._fb.logout(); } catch(e){} }
  currentUser=null;clearSession();updateAuthBtn();closeMyAccount();showToast('👋 Logged out.');
}

function updateAuthBtn(){
  const btn=document.getElementById('authNavBtn');
  const accBtn=document.getElementById('myAccBtn');
  if(!btn)return;
  if(currentUser){
    const initial=currentUser.name?currentUser.name[0].toUpperCase():'?';
    btn.textContent=initial+' '+(currentUser.name||'').split(' ')[0];
    btn.classList.add('logged-in');
    if(accBtn)accBtn.style.display='';
  } else {
    btn.textContent='👤 Login';
    btn.classList.remove('logged-in');
    if(accBtn)accBtn.style.display='none';
  }
}

function fillProfile(){
  if(!currentUser)return;
}

// Offline fallback session restore
(function(){
  const s=loadSession();
  if(s&&!isFirebaseReady()){currentUser=s;setTimeout(updateAuthBtn,100);}
})();

window.addEventListener('load',function(){
  const am=document.getElementById('authModal');
  const ma=document.getElementById('myAccountModal');
  if(am)am.addEventListener('click',function(e){if(e.target===this)closeAuth()});
  if(ma)ma.addEventListener('click',function(e){if(e.target===this)closeMyAccount()});
});


/* ============ XP / RANK SYSTEM ============ */
const RANKS = [
  {name:'IRON',   emoji:'⚙️',  min:0,   max:99,   color:'#9ca3af'},
  {name:'BRONZE', emoji:'🥉',  min:100, max:299,  color:'#cd7f32'},
  {name:'GOLD',   emoji:'🥇',  min:300, max:699,  color:'#c9a84c'},
  {name:'DIAMOND',emoji:'💎',  min:700, max:1499, color:'#67e8f9'},
  {name:'PREMIUM',emoji:'👑',  min:1500,max:99999,color:'#a855f7'},
];

function getRank(xp){
  return RANKS.slice().reverse().find(r=>xp>=r.min)||RANKS[0];
}

function getUserXP(user){
  // XP = designs_sold * 30 + orders * 5 + followers * 10
  const u = getUsers()[user.username] || user;
  const sold = u.designsSold || 0;
  const orders = u.orders || 0;
  const followers = u.followers || 0;
  return sold * 30 + orders * 5 + followers * 10;
}

/* ============ MY ACCOUNT MODAL ============ */
function openMyAccount(){
  if(!currentUser){openAuth();return;}
  fillMyAccount();
  document.getElementById('myAccountModal').style.display='flex';
}
function closeMyAccount(){
  document.getElementById('myAccountModal').style.display='none';
}

function fillMyAccount(){
  if(!currentUser)return;
  const users=getUsers();
  const u={...currentUser,...(users[currentUser.username]||{})};

  // Avatar
  const av=document.getElementById('accAvatar');
  av.textContent=u.name?u.name[0].toUpperCase():'👤';

  document.getElementById('accName').textContent=u.name||u.username;
  document.getElementById('accUsername').textContent='@'+u.username;

  // XP & Rank
  const xp=getUserXP(u);
  const rank=getRank(xp);
  const nextRank=RANKS.find(r=>r.min>xp);
  const pct=nextRank?Math.min(100,((xp-rank.min)/(nextRank.min-rank.min))*100):100;

  document.getElementById('accRankBadge').textContent=rank.emoji;
  document.getElementById('accRankName').textContent=rank.emoji+' '+rank.name;
  document.getElementById('accRankName').style.color=rank.color;
  document.getElementById('accXpLabel').textContent=xp+' XP'+(nextRank?' / '+nextRank.min+' XP':'');
  document.getElementById('accXpFill').style.width=pct+'%';
  document.getElementById('accNextRank').textContent=nextRank?'Next: '+nextRank.emoji+' '+nextRank.name+' ('+nextRank.min+' XP)':'👑 MAX RANK ACHIEVED';

  // Stats
  document.getElementById('accFollowers').textContent=u.followers||0;
  document.getElementById('accFollowing').textContent=u.following||0;
  document.getElementById('accDesigns').textContent=u.designsPublished||0;

  // Info
  const ph=document.getElementById('accPhone');
  if(u.phone){ph.textContent='📞 '+u.phone;ph.style.display='block';}else{ph.style.display='none';}
  document.getElementById('accJoined').textContent='📅 Member since: '+u.joined;
  document.getElementById('accOrders').textContent='📦 Orders placed: '+(u.orders||0);

  // Rank tiers list
  document.getElementById('rankTiersList').innerHTML=RANKS.map(r=>`
    <div style="display:flex;align-items:center;gap:.6rem;padding:.3rem .4rem;border-radius:6px;background:${xp>=r.min?'rgba(201,168,76,.1)':'transparent'};border:1px solid ${xp>=r.min?r.color+'44':'transparent'}">
      <span style="font-size:1rem">${r.emoji}</span>
      <span style="font-size:12px;font-weight:700;color:${r.color};flex:1">${r.name}</span>
      <span style="font-size:11px;color:var(--txt3)">${r.min}${r.max<99999?' – '+r.max:'+' } XP</span>
      ${xp>=r.min?'<span style="font-size:10px;color:'+r.color+'">✓ UNLOCKED</span>':''}
    </div>`).join('');
}

/* ============ DISCOUNT CODES ============ */
const DISCOUNT_CODES = {
  'A3M10': 10,   // 10% off
  'A3M20': 20,   // 20% off
  'A3M50': 50,   // 50% off
  'LAUNCH': 15,  // 15% off
  'VIP30': 30,   // 30% off
};
let activeDiscount = 0;

function applyDiscount(){
  const code = document.getElementById('discountCodeInput').value.trim().toUpperCase();
  const msg = document.getElementById('discountMsg');
  const row = document.getElementById('discountRow');
  if(!code){msg.textContent='Enter a discount code.';msg.style.color='var(--txt4)';return;}
  if(DISCOUNT_CODES[code]!==undefined){
    activeDiscount = DISCOUNT_CODES[code];
    msg.textContent='✅ Code "'+code+'" applied! '+activeDiscount+'% off';
    msg.style.color='#22c55e';
    row.style.display='flex';
    updateCart();
    showToast('🏷️ Discount '+activeDiscount+'% applied!');
  } else {
    activeDiscount=0;
    msg.textContent='❌ Invalid code. Try: A3M10, A3M20, LAUNCH, VIP30';
    msg.style.color='#ef4444';
    row.style.display='none';
    updateCart();
  }
}

/* ============ PATCH updateCart to support discounts ============ */
const _origUpdateCart = updateCart;
updateCart = function(){
  _origUpdateCart();
  if(activeDiscount>0 && cart.length>0){
    const el=document.getElementById('cartTotalVal');
    if(el){
      const rawNum=el.textContent.replace(/[^0-9.]/g,'');
      const raw=parseFloat(rawNum)||0;
      if(raw>0){
        const saved=raw*(activeDiscount/100);
        const discounted=raw-saved;
        const cur=currency==='USD'?'$':'DZD ';
        el.textContent=currency==='USD'?'$'+discounted.toFixed(2):'DZD '+Math.round(discounted);
        const sv=document.getElementById('discountSavingsVal');
        if(sv)sv.textContent='-'+(currency==='USD'?'$'+saved.toFixed(2):'DZD '+Math.round(saved));
      }
    }
  } else {
    const row=document.getElementById('discountRow');
    if(row)row.style.display='none';
  }
};

/* ============ HERO HOOK ANIMATION ============ */
const HERO_HOOKS = [
  "Print your ideas — make them real.",
  "From your mind to the fabric.",
  "Your design. Your story. Printed.",
  "Wear what you imagine.",
  "Create. Print. Stand out.",
];
let hookIdx=0;
function animateHook(){
  const el=document.getElementById('heroSub');
  if(!el)return;
  el.style.opacity='0';
  el.style.transform='translateY(8px)';
  setTimeout(()=>{
    hookIdx=(hookIdx+1)%HERO_HOOKS.length;
    el.textContent=HERO_HOOKS[hookIdx];
    el.style.transition='opacity .5s,transform .5s';
    el.style.opacity='1';
    el.style.transform='translateY(0)';
  },400);
}
document.getElementById('heroSub').style.transition='opacity .5s,transform .5s';
setInterval(animateHook, 3500);

/* ============ FIREBASE STATUS INDICATOR ============ */
setTimeout(function(){
  const dot = document.getElementById('fbStatusDot');
  const txt = document.getElementById('fbStatusTxt');
  if(!dot || !txt) return;
  if(window._fb && window._fb.ready()){
    dot.style.background = '#22c55e';
    txt.textContent = '🔥 Firebase connected — accounts saved to cloud';
  } else {
    dot.style.background = '#f59e0b';
    txt.textContent = '⚠️ Firebase not configured — running in offline mode';
  }
}, 2000);